      "content": "// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = {};

module.exports = {
  getProjectById(id) {
    return projectsStore[id];
  },
  getProjectByName(name) {
    for (const id in projectsStore) {
      if (projectsStore[id].name === name) {
        return projectsStore[id];
      }
    }
    return null;
  },
  createProject(name) {
    const projectId = randomUUID();
    projectsStore[projectId] = { id: projectId, name: name, members: [], tasks: [] };
    return projectsStore[projectId];
  }
};
