const projectsService = require('../../modules/projects/service');

module.exports = {
  createTask(projectId, description) {
    const project = projectsService.getProjectById(projectId);
    if (!project) return null;
    const taskId = randomUUID();
    project.tasks.push({ id: taskId, description: description, status: 'todo' });
    return project;
  },
  updateTaskStatus(projectId, taskId, newStatus) {
    const project = projectsService.getProjectById(projectId);
    if (!project) return null;
    const task = project.tasks.find(task => task.id === taskId);
    if (!task || (newStatus !== 'todo' && newStatus !== 'done')) return null;
    task.status = newStatus;
    return project;
  }
};
